/* BTCommand — command palette / search menu.
 * Figma: D-Command 2461-2206 (web only).
 * Shared between Vue (BTCommand.vue) and React (BTCommand.tsx) — one file, zero duplication.
 */

/* ── Root container ──────────────────────────────────────────────────────── */

.bt-command {
  position: relative;
  display: flex;
  flex-direction: column;
  width: 100%;
  background: var(--bg-primary);
  border: 1px solid var(--border-tertiary);
  border-radius: 12px;
  box-shadow: var(--shadow-elevation-md);
  overflow: hidden;
  font-family: var(--typography-font-family-sans);
}

/* ── Search area ─────────────────────────────────────────────────────────── */

.bt-command__search {
  padding: var(--space-sm);
  background: var(--bg-primary);
  border-bottom: 1px solid var(--border-primary);
}

/* BTInputSearch inside command — remove validation row, fit command layout */
.bt-command__search .bt-input-search {
  width: 100%;
}

/* ── Separator ───────────────────────────────────────────────────────────── */

.bt-command__separator {
  height: 1px;
  background: var(--border-primary);
  border: none;
  margin: 0;
}

/* ── List ────────────────────────────────────────────────────────────────── */

.bt-command__list {
  max-height: 384px;
}

/* ── Group ───────────────────────────────────────────────────────────────── */

.bt-command__group {
  padding: 6px var(--space-sm);
}

.bt-command__group-heading {
  padding: var(--space-sm);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-sm);
  color: var(--text-primary);
  opacity: 0.5;
}

/* ── Empty ───────────────────────────────────────────────────────────────── */

.bt-command__empty {
  padding: var(--space-xl) var(--space-sm);
  text-align: center;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
}

/* ── Item ────────────────────────────────────────────────────────────────── */

.bt-command__item {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  padding: var(--space-sm);
  border-radius: var(--radius-xs);
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  user-select: none;
  transition: background-color 100ms ease;
  outline: none;
}

.bt-command__item:hover,
.bt-command__item--highlighted {
  background: var(--bg-subtle);
}

.bt-command__item[aria-disabled="true"] {
  opacity: 0.5;
  cursor: default;
  pointer-events: none;
}

.bt-command__item-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  color: var(--icon-primary);
}

.bt-command__item-icon > svg {
  width: 16px;
  height: 16px;
  display: block;
}

.bt-command__item-label {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* ── Shortcut ────────────────────────────────────────────────────────────── */

.bt-command__shortcut {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2xs);
  flex-shrink: 0;
  margin-inline-start: auto;
}

.bt-command__kbd {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 16px;
  min-width: 16px;
  padding: var(--space-2xs);
  background: var(--bg-subtle);
  border-radius: var(--radius-xs);
  font-size: var(--typography-font-size-2xs);
  font-weight: 700;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  font-family: inherit;
}

/* ── Dialog backdrop ─────────────────────────────────────────────────────── */

.bt-command-dialog__backdrop {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: flex-start;
  justify-content: center;
  padding: 80px var(--space-lg) var(--space-lg);
  /* Raw rgba allowed (CLAUDE.md §6) — opacity overlay, not a named colour token. */
  background: rgba(0, 0, 0, 0.5);
  z-index: 9100;
}

.bt-command-dialog__panel {
  width: 100%;
  max-width: 500px;
}

/* ── Dialog transitions ──────────────────────────────────────────────────── */

.bt-command-dialog-enter-active,
.bt-command-dialog-leave-active {
  transition: opacity 150ms ease, transform 150ms ease;
}

.bt-command-dialog-enter-from,
.bt-command-dialog-leave-to {
  opacity: 0;
  transform: scale(0.97) translateY(-4px);
}

.bt-command-dialog-enter-to,
.bt-command-dialog-leave-from {
  opacity: 1;
  transform: scale(1) translateY(0);
}

/**
 * BTCommand — command palette / search menu (React, web only).
 * Figma: D-Command 2461-2206.
 *
 * Compound component — compose sub-components to build the palette:
 * BTCommand, BTCommandInput, BTCommandList, BTCommandEmpty,
 * BTCommandGroup, BTCommandItem, BTCommandSeparator,
 * BTCommandShortcut, BTCommandDialog
 *
 * @example
 * ```tsx
 * <BTCommand onSelect={(val) => console.log(val)}>
 *   <BTCommandInput placeholder="Type a command…" />
 *   <BTCommandList>
 *     <BTCommandEmpty />
 *     <BTCommandGroup heading="Navigation">
 *       <BTCommandItem value="home">Home</BTCommandItem>
 *       <BTCommandItem value="settings">Settings</BTCommandItem>
 *     </BTCommandGroup>
 *   </BTCommandList>
 * </BTCommand>
 * ```
 *
 * @example BTCommandDialog
 * ```tsx
 * const [open, setOpen] = useState(false);
 * <BTCommandDialog open={open} onOpenChange={setOpen}>
 *   <BTCommandInput />
 *   <BTCommandList>
 *     <BTCommandEmpty />
 *     <BTCommandGroup heading="Actions">
 *       <BTCommandItem value="new-file" onSelect={() => createFile()}>
 *         New File
 *         <BTCommandShortcut keys="⌘N" />
 *       </BTCommandItem>
 *     </BTCommandGroup>
 *   </BTCommandList>
 * </BTCommandDialog>
 * ```
 */
import './BTCommand.css';
import * as React from 'react';
import { BTInputSearch } from '../input-search/BTInputSearch';
import { BTScrollbar } from '../scrollbar/BTScrollbar';

// ── Context ───────────────────────────────────────────────────────────────

interface BTCommandCtx {
  query: string;
  setQuery: (q: string) => void;
  highlighted: string | null;
  setHighlighted: (v: string | null) => void;
  itemValues: React.MutableRefObject<string[]>;
  visibleSet: React.MutableRefObject<Set<string>>;
  visibleVersion: number; // bumped to trigger re-renders
  registerItem: (value: string) => void;
  unregisterItem: (value: string) => void;
  setItemVisible: (value: string, visible: boolean) => void;
  moveHighlight: (dir: 1 | -1) => void;
  selectHighlighted: () => void;
  onSelect: (value: string) => void;
}

const CommandContext = React.createContext<BTCommandCtx | null>(null);

function useCommandCtx(): BTCommandCtx {
  const ctx = React.useContext(CommandContext);
  if (!ctx) throw new Error('BTCommand sub-components must be inside BTCommand');
  return ctx;
}

// ── BTCommand ─────────────────────────────────────────────────────────────

export interface BTCommandProps {
  children?: React.ReactNode;
  onSelect?: (value: string) => void;
  className?: string;
}

export function BTCommand({ children, onSelect, className }: BTCommandProps) {
  const [query, setQuery] = React.useState('');
  const [highlighted, setHighlighted] = React.useState<string | null>(null);
  const [visibleVersion, setVisibleVersion] = React.useState(0);
  const itemValues = React.useRef<string[]>([]);
  const visibleSet = React.useRef<Set<string>>(new Set());

  const bumpVisible = () => setVisibleVersion((v) => v + 1);

  const registerItem = React.useCallback((value: string) => {
    if (!itemValues.current.includes(value)) itemValues.current.push(value);
    visibleSet.current.add(value);
    bumpVisible();
  }, []);

  const unregisterItem = React.useCallback((value: string) => {
    const idx = itemValues.current.indexOf(value);
    if (idx !== -1) itemValues.current.splice(idx, 1);
    visibleSet.current.delete(value);
    setHighlighted((h) => (h === value ? null : h));
    bumpVisible();
  }, []);

  const setItemVisible = React.useCallback(
    (value: string, visible: boolean) => {
      if (visible) {
        visibleSet.current.add(value);
      } else {
        visibleSet.current.delete(value);
        setHighlighted((h) => (h === value ? null : h));
      }
      bumpVisible();
    },
    [],
  );

  const moveHighlight = React.useCallback(
    (dir: 1 | -1) => {
      const visible = itemValues.current.filter((v) => visibleSet.current.has(v));
      if (!visible.length) return;
      setHighlighted((prev) => {
        const idx = prev !== null ? visible.indexOf(prev) : -1;
        const next = (idx + dir + visible.length) % visible.length;
        return visible[next] ?? prev;
      });
    },
    [],
  );

  const handleSelect = React.useCallback(
    (value: string) => { onSelect?.(value); },
    [onSelect],
  );

  const selectHighlighted = React.useCallback(() => {
    setHighlighted((h) => {
      if (h !== null) handleSelect(h);
      return h;
    });
  }, [handleSelect]);

  function onKeyDown(e: React.KeyboardEvent) {
    if (e.key === 'ArrowDown') { e.preventDefault(); moveHighlight(1); }
    else if (e.key === 'ArrowUp') { e.preventDefault(); moveHighlight(-1); }
    else if (e.key === 'Enter') { e.preventDefault(); selectHighlighted(); }
  }

  const ctx: BTCommandCtx = {
    query,
    setQuery,
    highlighted,
    setHighlighted,
    itemValues,
    visibleSet,
    visibleVersion,
    registerItem,
    unregisterItem,
    setItemVisible,
    moveHighlight,
    selectHighlighted,
    onSelect: handleSelect,
  };

  return (
    <CommandContext.Provider value={ctx}>
      <div
        className={['bt-command', className].filter(Boolean).join(' ')}
        role="combobox"
        aria-haspopup="listbox"
        aria-expanded
        onKeyDown={onKeyDown}
      >
        {children}
      </div>
    </CommandContext.Provider>
  );
}

BTCommand.displayName = 'BTCommand';

// ── BTCommandInput ────────────────────────────────────────────────────────

export interface BTCommandInputProps {
  placeholder?: string;
}

export function BTCommandInput({
  placeholder = 'Type a command to search',
}: BTCommandInputProps) {
  const ctx = useCommandCtx();
  return (
    <div className="bt-command__search">
      <BTInputSearch
        value={ctx.query}
        onChange={(v) => ctx.setQuery(v)}
        placeholder={placeholder}
        className="bt-command__search-input-search"
      />
    </div>
  );
}

BTCommandInput.displayName = 'BTCommandInput';

// ── BTCommandList ─────────────────────────────────────────────────────────

export interface BTCommandListProps {
  children?: React.ReactNode;
}

export function BTCommandList({ children }: BTCommandListProps) {
  return (
    <BTScrollbar className="bt-command__list" role="listbox">
      {children}
    </BTScrollbar>
  );
}

BTCommandList.displayName = 'BTCommandList';

// ── BTCommandEmpty ────────────────────────────────────────────────────────

export interface BTCommandEmptyProps {
  children?: React.ReactNode;
}

export function BTCommandEmpty({ children = 'No results found.' }: BTCommandEmptyProps) {
  const ctx = useCommandCtx();
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const _v = ctx.visibleVersion; // subscribe to visibility changes
  const shouldShow = ctx.query.length > 0 && ctx.visibleSet.current.size === 0;
  if (!shouldShow) return null;
  return (
    <div className="bt-command__empty" aria-live="polite">
      {children}
    </div>
  );
}

BTCommandEmpty.displayName = 'BTCommandEmpty';

// ── BTCommandGroup ────────────────────────────────────────────────────────

interface GroupCtx {
  registerGroupItem: (value: string) => void;
  unregisterGroupItem: (value: string) => void;
}

const GroupContext = React.createContext<GroupCtx | null>(null);

export interface BTCommandGroupProps {
  heading?: string;
  children?: React.ReactNode;
}

export function BTCommandGroup({ heading, children }: BTCommandGroupProps) {
  const ctx = useCommandCtx();
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const _v = ctx.visibleVersion;
  const groupItems = React.useRef<string[]>([]);

  const registerGroupItem = React.useCallback((value: string) => {
    if (!groupItems.current.includes(value)) groupItems.current.push(value);
  }, []);

  const unregisterGroupItem = React.useCallback((value: string) => {
    const idx = groupItems.current.indexOf(value);
    if (idx !== -1) groupItems.current.splice(idx, 1);
  }, []);

  const isVisible =
    !ctx.query ||
    groupItems.current.some((v) => ctx.visibleSet.current.has(v));

  if (!isVisible) return null;

  return (
    <GroupContext.Provider value={{ registerGroupItem, unregisterGroupItem }}>
      <div className="bt-command__group" role="group" aria-label={heading}>
        {heading && <p className="bt-command__group-heading">{heading}</p>}
        {children}
      </div>
    </GroupContext.Provider>
  );
}

BTCommandGroup.displayName = 'BTCommandGroup';

// ── BTCommandItem ─────────────────────────────────────────────────────────

export interface BTCommandItemProps {
  value: string;
  disabled?: boolean;
  children?: React.ReactNode;
  onSelect?: (value: string) => void;
  /** Leading 16×16 icon. */
  icon?: React.ReactNode;
}

export function BTCommandItem({
  value,
  disabled = false,
  children,
  onSelect,
  icon,
}: BTCommandItemProps) {
  const ctx = useCommandCtx();
  const groupCtx = React.useContext(GroupContext);

  const isVisible = !ctx.query
    ? true
    : value.toLowerCase().includes(ctx.query.toLowerCase());

  const isHighlighted = ctx.highlighted === value;

  // ── Registration ────────────────────────────────────────────────────────
  React.useEffect(() => {
    ctx.registerItem(value);
    groupCtx?.registerGroupItem(value);
    return () => {
      ctx.unregisterItem(value);
      groupCtx?.unregisterGroupItem(value);
    };
    // run once on mount; value changes would be unusual
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  React.useEffect(() => {
    ctx.setItemVisible(value, isVisible);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isVisible, value]);

  if (!isVisible) return null;

  function handleClick() {
    if (disabled) return;
    onSelect?.(value);
    ctx.onSelect(value);
  }

  return (
    <div
      className={[
        'bt-command__item',
        isHighlighted ? 'bt-command__item--highlighted' : '',
      ].filter(Boolean).join(' ')}
      role="option"
      aria-selected={isHighlighted}
      aria-disabled={disabled || undefined}
      onClick={handleClick}
      onMouseEnter={() => { if (!disabled) ctx.setHighlighted(value); }}
      onMouseLeave={() => { if (ctx.highlighted === value) ctx.setHighlighted(null); }}
    >
      {icon != null && (
        <span className="bt-command__item-icon" aria-hidden>
          {icon}
        </span>
      )}
      <span className="bt-command__item-label">{children}</span>
    </div>
  );
}

BTCommandItem.displayName = 'BTCommandItem';

// ── BTCommandSeparator ────────────────────────────────────────────────────

export function BTCommandSeparator() {
  return <hr className="bt-command__separator" aria-hidden />;
}

BTCommandSeparator.displayName = 'BTCommandSeparator';

// ── BTCommandShortcut ─────────────────────────────────────────────────────

export interface BTCommandShortcutProps {
  /** Shortcut string (each char → badge) or array of key labels. */
  keys: string | string[];
}

export function BTCommandShortcut({ keys }: BTCommandShortcutProps) {
  const keyList = Array.isArray(keys) ? keys : keys.split('');
  return (
    <span className="bt-command__shortcut" aria-label="keyboard shortcut">
      {keyList.map((k, i) => (
        <kbd key={i} className="bt-command__kbd">{k}</kbd>
      ))}
    </span>
  );
}

BTCommandShortcut.displayName = 'BTCommandShortcut';

// ── BTCommandDialog ───────────────────────────────────────────────────────

export interface BTCommandDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  /** Global keyboard shortcut to toggle the dialog. @default '⌘K' */
  shortcut?: string;
  children?: React.ReactNode;
  onSelect?: (value: string) => void;
}

export function BTCommandDialog({
  open,
  onOpenChange,
  shortcut = '⌘K',
  children,
  onSelect,
}: BTCommandDialogProps) {
  // Global keyboard handler
  React.useEffect(() => {
    function handler(e: KeyboardEvent) {
      if (e.key === 'Escape' && open) {
        e.preventDefault();
        onOpenChange(false);
        return;
      }
      if (shortcut && e.key === 'k' && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        onOpenChange(!open);
      }
    }
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [open, onOpenChange, shortcut]);

  if (!open) return null;

  return (
    <div
      className="bt-command-dialog__backdrop"
      role="dialog"
      aria-modal
      aria-label="Command palette"
      onClick={(e) => { if (e.target === e.currentTarget) onOpenChange(false); }}
    >
      <div className="bt-command-dialog__panel">
        <BTCommand onSelect={onSelect}>
          {children}
        </BTCommand>
      </div>
    </div>
  );
}

BTCommandDialog.displayName = 'BTCommandDialog';
